#include <stdio.h>
int main() {
    int T, N, A[100005], count;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        count = 0;
        for (int i = 1; i < N; i++) {
            if (A[i] != A[0]) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

