code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int count = 0;
            for (int i = 1; i < N; i++) {
                if (A[i] != A[0]) {
                    count++;
                }
            }
            System.out.println(count);
        }
    }
}

