for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const A = readline().split(' ').map(x => parseInt(x));
    let count = 0;
    for (let j = 1; j < N; j++) {
        if (A[j] !== A[0]) {
            count++;
        }
    }
    console.log(count);
}
